class Solution:
    def containsCycle(self, grid):
        m, n = len(grid), len(grid[0])
        parent = list(range(m * n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def idx(r, c):
            return r * n + c
        for r in range(m):
            for c in range(n):
                cur = idx(r, c)
                if c + 1 < n and grid[r][c + 1] == grid[r][c]:
                    nb = idx(r, c + 1)
                    ra, rb = find(cur), find(nb)
                    if ra == rb:
                        return True
                    parent[ra] = rb
                if r + 1 < m and grid[r + 1][c] == grid[r][c]:
                    nb = idx(r + 1, c)
                    ra, rb = find(cur), find(nb)
                    if ra == rb:
                        return True
                    parent[ra] = rb
        return False

