class Solution:
    def containsCycle(self, grid):
        m, n = len(grid), len(grid[0])
        visited = [[False] * n for _ in range(m)]
        for si in range(m):
            for sj in range(n):
                if visited[si][sj]:
                    continue
                visited[si][sj] = True
                stack = [(si, sj, -1, -1)]
                while stack:
                    r, c, pr, pc = stack.pop()
                    ch = grid[r][c]
                    for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] == ch and (nr, nc) != (pr, pc):
                            if visited[nr][nc]:
                                return True
                            visited[nr][nc] = True
                            stack.append((nr, nc, r, c))
        return False

